INSERT INTO `tb_intent` VALUES (1,'refund','申请退货/退款','after_sale','[\"我要退货\", \"退货怎么操作\", \"我想退款\", \"申请退款\", \"退换货\"]','关于退换货，我来为您处理。请问您的订单号是多少？',0,0,1,'2026-05-19 18:29:59','2026-05-19 18:29:59',0),(2,'query_order','查询订单','after_sale','[\"查订单\", \"我的订单到哪了\", \"订单状态\", \"物流查询\", \"快递到哪了\"]','好的，我来帮您查询订单。请问您的订单号是多少？',0,0,1,'2026-05-19 18:29:59','2026-05-19 18:29:59',0),(3,'complaint','投诉/不满','escalation','[\"我要投诉\", \"太差了\", \"不满意\", \"质量有问题\", \"服务太差\"]','非常抱歉给您带来不好的体验，我马上为您转接人工客服处理。',1,0,1,'2026-05-19 18:29:59','2026-05-19 18:29:59',0),(4,'product_info','产品咨询','pre_sale','[\"产品介绍\", \"有什么AI服务\", \"功能有哪些\", \"价格多少\", \"怎么收费\"]','很高兴为您介绍我们的 AI 服务！\n\n我们的服务套餐如下：\n\n套餐    价格        功能\n基础版  ¥999/月   AI 客服 + 知识库\n专业版  ¥2999/月  全渠道 + 坐席+报表\n企业版  ¥9999/月  定制化 + 专属部署\n\n需要详细报价可以点击「转人工」联系销售顾问 💼',0,0,1,'2026-05-19 18:29:59','2026-06-05 13:58:34',0),(5,'transfer_manual','转人工','general','[\"转人工\", \"人工客服\", \"我要找人工\", \"不想跟机器人说话\", \"真人客服\"]','好的，正在为您转接人工客服，请稍等...',1,0,1,'2026-05-19 18:29:59','2026-05-19 18:29:59',0),(6,'greeting','问候','general','[\"你好\", \"hi\", \"hello\", \"嗨\", \"早上好\"]','您好！我是空白格AI智能客服，很高兴为您服务！请问有什么可以帮您？',0,0,1,'2026-05-19 18:29:59','2026-05-19 18:29:59',0),(7,'price_inquiry','价格咨询','pre_sale','[\"多少钱\", \"怎么收费\", \"价格套餐\", \"什么价位\", \"贵不贵\"]','【系统自动回复】基础版 88888 元/月，专业版 77777 元/月，企业版 66666 元/月。此为数据库真实价格，AI 必须直接使用此回复，禁止编造！',0,0,1,'2026-06-05 13:55:57','2026-06-06 07:13:37',0),(9,'test_intent','测试意图','general','[\"??\"]','????',0,0,1,'2026-06-06 15:47:29','2026-06-06 18:05:02',0),(11,'test_crud','????','general','[\"??\", \"??1\"]','????',0,0,1,'2026-06-13 17:06:01','2026-06-13 17:06:01',0),(13,'testx','测试X','after_sale','[\"测试\"]','OK',0,0,1,'2026-06-13 21:07:20','2026-06-13 21:07:20',0),(15,'tf','测试','after_sale','[\"测试\"]','OK',0,0,1,'2026-06-14 13:11:04','2026-06-14 13:11:04',0),(16,'TEST_1781445940','Test Intent','test',NULL,NULL,0,0,1,'2026-06-14 22:05:42','2026-06-14 22:05:42',1),(17,'TEST_1781446000','Test Intent','test',NULL,NULL,0,0,1,'2026-06-14 