CREATE TABLE `tb_kb_item` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '条目ID',
  `category_id` bigint DEFAULT NULL COMMENT '分类ID',
  `industry_id` bigint DEFAULT NULL COMMENT '所属行业 ID',
  `item_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'faq' COMMENT '类型：faq/document/table/api',
  `question` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '问题/标题',
  `answer` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '答案/内容',
  `similar_questions` json DEFAULT NULL COMMENT '相似问法列表（["怎么退货","退货流程"]）',
  `keywords` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关键词（逗号分隔）',
  `tags` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '标签（逗号分隔）',
  `priority` int DEFAULT '0' COMMENT '优先级（数值越大优先级越高）',
  `hit_count` int DEFAULT '0' COMMENT '命中次数',
  `like_count` int DEFAULT '0' COMMENT '点赞数',
  `dislike_count` int DEFAULT '0' COMMENT '点踩数',
  `effective_start` datetime DEFAULT NULL COMMENT '有效期开始',
  `effective_end` datetime DEFAULT NULL COMMENT '有效期结束',
  `version` int DEFAULT '1' COMMENT '版本号',
  `status` tinyint DEFAULT '1' COMMENT '状态：0-禁用，1-启用，2-待审核',
  `create_by` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'system' COMMENT '创建人',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '是否删除：0-否，1-是',
  PRIMARY KEY (`id`),
  KEY `idx_category_id` (`category_id`),
  KEY `idx_item_type` (`item_type`),
  KEY `idx_status` (`status`),
  KEY `idx_industry` (`industry_id`),
  FULLTEXT KEY `ft_question` (`question`) /*!50100 WITH PARSER `ngram` */ ,
  FULLTEXT KEY `ft_keywords` (`keywords`) /*!50100 WITH PARSER `ngram` */ 
) ENGINE=InnoDB AUTO_INCREMENT=74 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='知识库条目表';
