INSERT INTO `tb_kb_item` VALUES (1,6,10,'faq','如何申请退货？','您可以在收到商品后7天内申请退货。操作步骤：\n1. 登录账户 → 我的订单\n2. 选择需退货的订单 → 申请退货\n3. 填写退货原因并提交\n4. 等待审核（1-2个工作日）\n5. 审核通过后按指引寄回商品','[\"怎么退货\", \"退货流程\", \"我想退货\", \"如何退款\", \"退款怎么操作\"]','退货,退款,退换货',NULL,10,2,0,0,NULL,NULL,1,1,'system','2026-05-19 18:29:59','2026-05-25 15:18:32',0),(2,7,10,'faq','如何查询物流信息？','查询物流的方法：\n1. 登录账户 → 我的订单\n2. 点击订单号 → 查看物流详情\n3. 也可直接在快递100输入运单号查询\n\n如物流超过5天未更新，请联系客服处理。','[\"物流怎么查\", \"快递到哪了\", \"查询快递\", \"配送进度\", \"什么时候到货\"]','物流,快递,配送,运单',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-19 18:29:59','2026-05-25 15:18:32',0),(3,1,10,'faq','你们提供哪些AI服务？','空白格·AI提供以下核心服务：\n\n🤖 AI智能客服 — 7×24小时自动应答\n✍️ AI自媒体运营 — 爆款文案自动生成\n💻 AI编程与运维 — 智能代码补全\n🚀 AI应用部署 — 一键云端部署\n🛒 AI电商运营 — 智能推荐+评论分析\n🎨 AI设计与创意 — AI图片/Logo生成\n\n详细方案可咨询人工客服或访问官网 www.jnysx.cn','[\"你们做什么的\", \"AI 服务有哪些\", \"产品介绍\", \"空白格做什么\", \"你们公司做什么\", \"我想接入 AI 客服系统\", \"如何接入客服系统\", \"客服系统怎么弄\", \"AI 客服怎么接入\"]','AI,服务,产品,介绍',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-19 18:29:59','2026-06-13 21:15:27',1),(4,4,10,'faq','你们公司是做什么的？','济南空白格网络科技有限公司是一家专注AI应用方案落地的科技公司。我们的使命是让AI不再是概念，而是每个企业触手可及的生产力工具。\n\n核心优势：\n- 技术扎实：全栈自研，保证交付质量\n- 服务贴心：从沟通到上线全程陪伴\n- 持续迭代：上线不是结束，持续优化至满意','[\"公司介绍\", \"你们是谁\", \"空白格是什么\", \"公司信息\", \"空白格科技是做什么的\", \"空白格科技主营业务\", \"你们公司业务\", \"主要做什么业务\"]','公司,介绍,关于',NULL,5,0,0,0,NULL,NULL,1,1,'system','2026-05-19 18:29:59','2026-05-25 19:39:53',0),(5,NULL,10,'faq','你们公司在哪','公司地址：山东省济南市槐荫区AI应用大厦14楼 官网：www.jnysx.cn 商务邮箱：2210335130@qq.com','[\"公司地址\", \"地址在哪\", \"公司地址在哪\", \"地址是什么\", \"公司地址是什么\", \"在哪办公\", \"办公地点\"]',NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-24 12:42:27','2026-05-25 21:40:04',0),(6,3,10,'faq','你们公司在哪','公司地址：山东省济南市槐荫区AI应用大厦14楼 官网：www.jnysx.cn 商务邮箱：2210335130@qq.com','[\"公司地址\", \"地址在哪\", \"公司地址在哪\", \"地址是什么\", \"公司地址是什么\", \"在哪办公\", \"办公地点\"]',NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-24 12:42:28','2026-05-25 21:40:04',0),(7,NULL,10,'faq','你们的联系方式是什么','📧 商务邮箱：2210335130@qq.com\n🌐 官网：www.jnysx.cn\n📍 地址：山东省济南市槐荫区AI应用大厦14楼\n⏰ 工作时间：周一至周五 9:00-18:00',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-24 12:43:23','2026-05-25 15:18:32',0),(8,NULL,10,'faq','空白格科技的官网是什么','我们的官网是 www.jnysx.cn\n\n📧 商务合作邮箱：2210335130@qq.com\n📍 公司地址：山东省济南市槐荫区AI应用大厦14楼',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-24 12:43:23','2026-05-25 15:18:32',0),(9,NULL,10,'faq','你们的工作时间是几点','人工客服工作时间：周一至周五 9:00-18:00\n\nAI 客服 7×24 小时在线，随时为您解答问题。\n\n📧 邮箱：2210335130@qq.com（非工作时间可邮件联系）',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-24 12:43:23','2026-05-25 15:18:32',0),(10,NULL,1,'faq','如何查询订单状态','登录账户 → 我的订单 → 查看订单详情，可实时跟踪物流信息。','[\"查订单\", \"订单在哪\", \"物流信息\"]','订单，物流，查询',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(11,NULL,1,'faq','退货流程是什么','登录账户→我的订单→申请退货→填写原因→寄回商品→退款。','[\"怎么退货\", \"退货流程\", \"我想退货\"]','退货，退款，退换货',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(12,NULL,1,'faq','多久发货','工作日下单后 24 小时内发货，节假日顺延。','[\"什么时候发货\", \"发货时间\", \"多久能到\"]','发货，时效，快递',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(13,NULL,1,'faq','支持哪些支付方式','支持支付宝、微信支付、银联卡、花呗分期等多种支付方式。','[\"能用什么付款\", \"支持花呗吗\", \"可以分期吗\"]','支付，付款，花呗，分期',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(14,NULL,1,'faq','有发票吗','支持开具电子发票和纸质发票。下单时选择开发票，填写抬头和税号即可。','[\"开发票\", \"增值税发票\", \"电子发票\"]','发票，报销，税票',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(15,NULL,2,'faq','有哪些课程','提供 K12 全科辅导、职业资格培训、IT 技能、语言学习等 100+ 课程。','[\"课程介绍\", \"学什么\", \"有什么课\"]','课程，培训，学习',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(16,NULL,2,'faq','如何报名','选择课程→填写报名信息→选择班型→完成支付→添加班主任微信。','[\"报名流程\", \"怎么报名\", \"如何购买\"]','报名，购买，流程',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(17,NULL,2,'faq','支持试听吗','所有课程均支持免费试听！在课程详情页点击立即试听，即可体验 15 分钟。','[\"能试听吗\", \"免费试听\", \"体验课\"]','试听，体验，免费',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(18,NULL,2,'faq','有老师答疑吗','每班配备主讲老师 + 辅导老师双师服务。课后有问题可在班级群提问，老师 24 小时内解答。','[\"有问题问谁\", \"老师答疑\", \"课后辅导\"]','答疑，老师，辅导',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(19,NULL,2,'faq','学完有证书吗','完成课程学习并通过考核后，颁发官方认证的结业证书。证书可在官网查询真伪。','[\"有证书吗\", \"结业证书\", \"官方认证\"]','证书，认证，就业',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(20,NULL,3,'faq','如何预约挂号','关注医院微信公众号→预约挂号→选择科室和医生→选择就诊时间→填写就诊人信息→支付挂号费。','[\"怎么挂号\", \"预约挂号\", \"网上挂号\"]','挂号，预约，微信',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(21,NULL,3,'faq','医保能报销吗','支持全国各省市医保在线支付。就诊时出示医保电子凭证，系统自动计算报销金额。','[\"医保报销\", \"能用医保吗\", \"医保支付\"]','医保，报销，支付',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(22,NULL,3,'faq','检查报告多久出','血常规等常规检查 30 分钟出结果；CT、核磁等大型检查 2-4 小时出结果。','[\"报告多久\", \"检查结果\", \"什么时候出结果\"]','检查，报告，结果',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(23,NULL,3,'faq','可以线上复诊吗','慢性病、常见病支持线上复诊。视频问诊医生，开具电子处方，药品快递到家。','[\"线上复诊\", \"视频问诊\", \"网络门诊\"]','复诊，线上，视频问诊',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(24,NULL,3,'faq','药品能配送吗','支持药品配送服务。医生开具处方后，在药房缴费时选择快递配送，1-3 天送达。','[\"送药上门\", \"药品配送\", \"快递药品\"]','药品，配送，快递',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(25,NULL,4,'faq','如何办理信用卡','线上申请：下载 APP→填写资料→提交审核→面签→激活。最快 3 分钟审批，额度最高 30 万。','[\"办信用卡\", \"申请信用卡\", \"信用卡办理\"]','信用卡，办理，申请',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(26,NULL,4,'faq','贷款利率是多少','个人信用贷款年化利率 3.85% 起，根据信用评级浮动。等额本息/先息后本可选，随借随还。','[\"贷款利息\", \"利率多少\", \"贷款贵吗\"]','贷款，利率，利息',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(27,NULL,4,'faq','如何查询余额','登录手机银行→账户管理→活期/定期存款查询。或发送短信\"余额\"到 955XX 查询。','[\"查余额\", \"还有多少钱\", \"账户余额\"]','余额，查询，账户',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(28,NULL,4,'faq','转账手续费多少','本行转账免费；跨行转账：1 万以下 2 元/笔，1-5 万 5 元/笔，5 万以上按 0.01% 收取。','[\"转账收费吗\", \"手续费多少\", \"转账贵吗\"]','转账，手续费，费用',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(29,NULL,4,'faq','如何挂失银行卡','立即拨打客服热线挂失，或通过手机银行→安全中心→卡片挂失。挂失后资金立即冻结。','[\"卡丢了\", \"银行卡挂失\", \"卡被盗\"]','挂失，盗刷，冻结',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(30,NULL,5,'faq','如何预订餐厅','选择城市→搜索餐厅→选择日期和时间→选择人数→提交预订。支持免费预订，到店付费。','[\"怎么订位\", \"预订餐位\", \"网上订座\"]','预订，餐厅，订位',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(31,NULL,5,'faq','酒店可以几点入住','标准入住时间 14:00 后，退房时间 12:00 前。支持提前入住和延迟退房，需视房态安排。','[\"入住时间\", \"几点入住\", \"退房时间\"]','酒店，入住，退房',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(32,NULL,5,'faq','保洁服务包含哪些','日常保洁、深度保洁、开荒保洁、家电清洗等。服务人员经过专业培训，自带清洁工具。','[\"保洁做什么\", \"服务内容\", \"打扫卫生\"]','保洁，清洁，家政',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(33,NULL,5,'faq','旅游有导游吗','跟团游含专业导游讲解；自由行可选配当地一日游，含导游和交通。','[\"有导游吗\", \"导游讲解\", \"跟团游\"]','旅游，导游，跟团',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(34,NULL,5,'faq','外卖多久能到','平均配送时间 30-45 分钟，具体以骑手实际配送为准。超时可获得平台红包补偿。','[\"外卖多久\", \"配送时间\", \"什么时候到\"]','外卖，配送，时间',NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:22:04','2026-05-25 15:22:04',0),(35,1,1,'faq','如何查询订单状态？','登录账户→我的订单→查看订单详情，可实时跟踪物流信息。支持按订单号、手机号、商品名查询。','[\"查订单\", \"订单在哪\", \"物流信息\", \"怎么查快递\"]','订单，物流，查询',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(36,1,1,'faq','退货流程是什么？','登录账户→我的订单→申请退货→填写原因→寄回商品→退款。7 天内可申请，需保持原包装。','[\"怎么退货\", \"退款流程\", \"退换货政策\", \"七天无理由\"]','退货，退款，售后',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(37,1,1,'faq','多久发货？','工作日 16 点前下单当天发货，其他时间下单次日发货。发货后 1-3 天送达。','[\"什么时候发货\", \"发货时间\", \"几天发货\"]','发货，时间，物流',NULL,9,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(38,1,1,'faq','支持哪些支付方式？','支持支付宝、微信支付、银联云闪付、花呗分期（3/6/12 期）、信用卡支付。','[\"能用什么付款\", \"支持花呗吗\", \"可以分期吗\"]','支付，付款，花呗，分期',NULL,8,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(39,1,1,'faq','如何修改收货地址？','订单未发货前：我的订单→修改地址；已发货后需联系人工客服协助处理。','[\"地址错了\", \"改地址\", \"收货人电话错了\"]','地址，修改，收货',NULL,8,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(40,2,2,'faq','课程如何购买？','选择课程→立即购买→填写信息→支付成功→开通学习权限。支持微信/支付宝/银行卡支付。','[\"怎么买课\", \"购买流程\", \"如何报名\"]','课程，购买，报名',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(41,2,2,'faq','课程有效期多久？','课程购买后永久有效，可随时回看。部分直播课赠送的录播内容有效期 1 年。','[\"能看多久\", \"过期吗\", \"有时间限制吗\"]','有效期，时间，权限',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(42,2,2,'faq','支持退款吗？','课程未观看超过 10% 可申请退款，扣除已学部分费用。超过 10% 不予退款，可转让学习权限。','[\"能退钱吗\", \"退款政策\", \"不满意能退吗\"]','退款，退款政策',NULL,9,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(43,2,2,'faq','有老师答疑吗？','配备专属学习群，主讲老师 + 助教老师双师答疑，工作日 9:00-22:00 在线解答。','[\"有问题问谁\", \"有人教吗\", \"答疑服务\"]','答疑，老师，服务',NULL,8,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(44,2,2,'faq','提供发票吗？','支持开具电子发票，购买时填写发票抬头和税号，课程完成后 3 个工作日内开具。','[\"能开发票吗\", \"发票怎么开\", \"报销凭证\"]','发票，报销，凭证',NULL,8,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(45,3,3,'faq','如何预约挂号？','选择科室→选择医生→选择就诊时间→填写就诊人信息→支付挂号费→预约成功。就诊前 1 小时可取消。','[\"怎么挂号\", \"预约医生\", \"网上挂号\"]','挂号，预约，医生',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(46,3,3,'faq','体检套餐有哪些？','很高兴为您介绍我们的 AI 服务！\n\n我们的服务套餐如下：\n\n套餐    价格        功能\n基础版  ¥999/月   AI 客服 + 知识库\n专业版  ¥2999/月  全渠道 + 坐席+报表\n企业版  ¥9999/月  定制化 + 专属部署\n\n需要详细报价可以点击「转人工」联系销售顾问 💼','[\"体检多少钱\", \"有什么套餐\", \"体检项目\"]','体检，套餐，价格',NULL,10,0,0,0,NULL,NULL,2,1,'system','2026-05-25 15:39:15','2026-06-05 13:58:34',0),(47,3,3,'faq','报告多久出结果？','血常规等基础检查当天出结果，生化检查 1-2 个工作日，病理检查 3-5 个工作日。可在小程序查看电子报告。','[\"多久拿报告\", \"检查结果\", \"什么时候出结果\"]','报告，结果，时间',NULL,9,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(48,3,3,'faq','支持医保报销吗？','已开通省市医保直结，就诊时出示医保电子凭证即可。异地医保需先自费后回参保地报销。','[\"能刷医保吗\", \"医保报销\", \"异地医保\"]','医保，报销，支付',NULL,9,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(49,3,3,'faq','可以在线复诊开药吗？','支持在线复诊，医生根据病情开具电子处方，药品可快递到家或到店自取。初诊患者需到院就诊。','[\"能网上开药吗\", \"在线问诊\", \"复诊开方\"]','复诊，开药，在线问诊',NULL,8,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(50,4,4,'faq','如何申请信用卡？','选择卡种→在线填写申请资料→上传身份证和收入证明→提交审核→3-5 个工作日出结果→邮寄卡片。','[\"怎么办信用卡\", \"申请流程\", \"需要什么材料\"]','信用卡，申请，办卡',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(51,4,4,'faq','贷款年化利率多少？','个人信用贷款年化利率 3.85%-15.4%，根据信用评级确定。抵押贷款年化利率 3.45% 起，具体以审批结果为准。','[\"贷款利息多少\", \"利率多少\", \"年化多少\"]','贷款，利率，利息',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(52,4,4,'faq','如何查询征信报告？','持本人身份证到中国人民银行分支机构或指定商业银行网点查询，也可通过中国人民银行征信中心官网查询。','[\"征信怎么查\", \"个人征信\", \"信用报告\"]','征信，信用，报告',NULL,9,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(53,4,4,'faq','理财产品保本吗？','根据资管新规，理财产品均不承诺保本保息。提供 R1-R5 风险等级产品，R1/R2 风险较低，适合稳健型投资者。','[\"理财安全吗\", \"保本吗\", \"风险大吗\"]','理财，保本，风险',NULL,9,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(54,4,4,'faq','转账限额是多少？','手机银行单笔限额 50 万，日累计 100 万；网银 U 盾单笔 500 万，日累计 1000 万。可在安全中心调整。','[\"能转多少钱\", \"转账限额\", \"限额多少\"]','转账，限额，额度',NULL,8,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(55,5,5,'faq','如何开通 API 接口？','登录控制台→API 管理→创建应用→获取 AppID 和 AppSecret→查看接口文档→调用测试。新用户赠送 1000 次免费调用额度。','[\"API 怎么申请\", \"接口调用\", \"如何接入\"]','API，接口，接入',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(56,5,5,'faq','支持哪些编程语言 SDK？','提供 Python、Java、Node.js、Go、PHP、C# 等主流语言 SDK，支持 RESTful API 和 gRPC 协议。','[\"有 Python 吗\", \"支持 Java 吗\", \"SDK 下载\"]','SDK，语言，Python，Java',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(57,5,5,'faq','服务可用性如何保障？','多机房异地容灾部署，SLA 可用性 99.95%，自动故障转移，数据三副本存储，提供 7×24 小时监控告警。','[\"稳定吗\", \"有 SLA 吗\", \"宕机怎么办\"]','可用性，SLA，稳定',NULL,9,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(58,5,5,'faq','如何计费？','【最终验证 v3】基础版 100 元/月，专业版 200 元/月，企业版 300 元/月','[\"多少钱\", \"怎么收费\", \"价格多少\"]','计费，价格，收费',NULL,9,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-06-06 09:29:25',0),(59,5,5,'faq','提供技术支持吗？','基础版提供工单支持（工作日 9-18 点），企业版提供专属技术群 +400 电话 + 远程协助，7×24 小时响应。','[\"有问题找谁\", \"技术支持\", \"售后服务\"]','技术支持，服务，售后',NULL,8,0,0,0,NULL,NULL,1,1,'system','2026-05-25 15:39:15','2026-05-25 15:39:15',0),(60,1,1,'faq','产品价格','【最终验证 v3】基础版 100 元/月，专业版 200 元/月，企业版 300 元/月',NULL,'价格，费用，多少钱，套餐，收费',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-06-05 17:09:52','2026-06-06 09:29:25',0),(61,1,1,'faq','产品价格','【最终验证 v3】基础版 100 元/月，专业版 200 元/月，企业版 300 元/月',NULL,'价格，费用，多少钱，套餐，收费',NULL,10,0,0,0,NULL,NULL,1,1,'system','2026-06-05 17:10:20','2026-06-13 21:15:27',1),(62,1,NULL,'faq','????','????',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-06-06 14:42:16','2026-06-06 14:42:16',0),(63,1,NULL,'faq','','test',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-06-06 14:54:20','2026-06-12 19:43:41',0),(65,1,NULL,'faq','??????-1780731959','?????????',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-06-06 15:46:01','2026-06-06 15:46:01',0),(66,1,NULL,'faq','','test',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-06-06 15:46:03','2026-06-12 19:43:41',0),(68,1,NULL,'faq','../../../../etc/passwd','test',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-06-06 15:46:03','2026-06-06 15:46:03',0),(69,1,NULL,'faq','!@#$%^&*()_+{}|:<>?','test',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-06-06 15:46:03','2026-06-06 15:46:03',0),(71,2,NULL,'faq','???? - API??','????API?????????',NULL,NULL,NULL,0,0,0,0,NULL,NULL,1,1,'system','2026-06-13 17:04:17','2026-06-13 17:04:17',0),(72,2,NULL,'fa