  `trigger_condition` json NOT NULL COMMENT '触发条件（停留时长>120/购物车金额>100等）',
  `target_user_tags` json DEFAULT NULL COMMENT '目标用户标签',
  `message_template` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息模板',
