DROP TABLE IF EXISTS `tb_message`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_message` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '消息ID',
  `session_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会话ID',
  `msg_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'text' COMMENT '消息类型：text/image/card/video/file/link/quick_reply/form/system',
  `sender_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '发送者类型：user/agent/bot/system',
  `sender_id` bigint DEFAULT NULL COMMENT '发送者ID（用户ID/客服ID/0表示系统）',
  `sender_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '发送者名称',
  `sender_avatar` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '发送者头像',
  `content` text COLLATE utf8mb4_unicode_ci COMMENT '消息文本内容',
  `media_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '媒体文件URL（图片/视频/文件）',
  `media_type` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '媒体类型：image/jpeg/video/mp4等',
  `card_data` json DEFAULT NULL COMMENT '卡片数据（标题/描述/图片/按钮列表）',
  `quick_replies` json DEFAULT NULL COMMENT '快捷回复按钮列表（[{"label":"退货","value":"refund"}]）',
  `form_data` json DEFAULT NULL COMMENT '表单数据（槽位填槽/工单字段）',
  `intent` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '识别到的意图',
  `entities` json DEFAULT NULL COMMENT '抽取到的实体（[{"type":"order_no","value":"12345"}]）',
  `sentiment` tinyint DEFAULT NULL COMMENT '情感：0-中性，1-正面，-1-负面',
  `is_read` tinyint DEFAULT '0' COMMENT '是否已读：0-未读，1-已读',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_session_id` (`session_id`),
  KEY `idx_sender_type` (`sender_type`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=900 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='消息表';
