--
-- Table structure for table `tb_operation_log`
--

DROP TABLE IF EXISTS `tb_operation_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_operation_log` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `operator_id` bigint DEFAULT NULL COMMENT '操作人ID',
  `operator_type` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'system' COMMENT '操作人类型：admin/agent/system',
  `module` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模块：knowledge_base/intent/agent/channel/ticket/config',
  `action` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '动作：create/update/delete/import/export',
