  `mode` tinyint NOT NULL DEFAULT '0' COMMENT '对话模式：0-AI自动，1-AI+人工辅助',
  `user_ip` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '用户IP地址',
