  `end_reason` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '结束原因：user_close/agent_close/timeout/system',
  `csat_score` tinyint DEFAULT NULL COMMENT '满意度评分：1-5',
  `csat_comment` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '满意度评价内容',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '是否删除：0-否，1-是',
  `industry_id` bigint DEFAULT NULL COMMENT '行业 ID',
