DROP TABLE IF EXISTS `tb_skill_group`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_skill_group` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键 ID',
  `name` varchar(100) NOT NULL COMMENT '技能组名称',
  `code` varchar(50) NOT NULL COMMENT '技能组编码',
  `description` varchar(500) DEFAULT NULL COMMENT '描述',
  `priority` int DEFAULT '10' COMMENT '优先级（数字越小优先级越高）',
  `max_concurrent` int DEFAULT '5' COMMENT '最大并发会话数',
  `enabled` int DEFAULT '1' COMMENT '是否启用（0-否，1-是）',
  `intent_codes` varchar(500) DEFAULT NULL COMMENT '关联意图代码（逗号分隔）',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted` int DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_code` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='技能组表';
