DROP TABLE IF EXISTS `tb_ticket`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_ticket` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '工单ID',
  `ticket_no` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单编号（TK-20260519-001）',
  `session_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联会话ID',
  `user_id` int DEFAULT '1',
  `assignee_id` bigint DEFAULT NULL,
  `assignee_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `category` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单标题',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '问题描述',
  `intent_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sentiment_score` int DEFAULT NULL,
  `attachments` json DEFAULT NULL COMMENT '附件列表（[{"name":"截图.png","url":"..."}]）',
  `priority` tinyint DEFAULT '1' COMMENT '优先级：1-低，2-中，3-高，4-紧急',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `creator_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sla_deadline` datetime DEFAULT NULL COMMENT 'SLA截止时间',
  `form_data` json DEFAULT NULL COMMENT '自定义表单数据',
  `resolution` text COLLATE utf8mb4_unicode_ci COMMENT '解决方案',
  `solution` text COLLATE utf8mb4_unicode_ci COMMENT '工单解决方案',
  `satisfaction` int DEFAULT NULL,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '是否删除：0-否，1-是',
  `ticket_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'general',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_ticket_no` (`ticket_no`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_agent_id` (`assignee_id`),
  KEY `idx_status` (`status`),
  KEY `idx_category` (`category`)
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='工单表';
/*!40101 SET character_set_client = @saved_cs_client */;

