CREATE TABLE `tb_unknown_question` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `question` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '未匹配的问题',
  `session_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '来源会话ID',
  `similar_known_id` bigint DEFAULT NULL COMMENT '相似已知问题ID（建议归并）',
  `status` tinyint DEFAULT '0' COMMENT '状态：0-待处理，1-已补充答案，2-已忽略，3-已归并',
  `suggested_answer` text COLLATE utf8mb4_unicode_ci COMMENT '建议答案（人工补充）',
  `handle_by` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '处理人',
  `handle_time` datetime DEFAULT NULL COMMENT '处理时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_status` (`status`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='未知问题表（自学习）';
