--
-- Table structure for table `tb_user_behavior`
--

DROP TABLE IF EXISTS `tb_user_behavior`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_user_behavior` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '行为ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `behavior_type` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '行为类型：browse-浏览，purchase-购买，consult-咨询，click-点击',
  `target_id` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '目标对象ID（商品ID/页面URL等）',
  `target_type` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '目标类型：product/page/article等',
  `extra_data` json DEFAULT NULL COMMENT '附加数据（浏览时长、购买金额等）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_behavior_type` (`behavior_type`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户行为记录表';
